// criando variáveis
let primeiroValor = 35;
let segundoValor = 15;
console.log(`Primeiro valor = ${primeiroValor}`);
console.log(`Segundo valor = ${segundoValor}`);
// efetuando incremento
primeiroValor++;
//efetuando decremento
segundoValor--;
console.log(`-----------------------------------`);
console.log(`Exibindo após utilizar operadores`);
console.log(`Primeiro valor = ${primeiroValor}`);
console.log(`Segundo valor = ${segundoValor}`);